-- BATCH 6: LIFESTYLE (3 templates)

INSERT INTO dream_templates (slug, title, category, description, emoji, color, big_wins, small_wins, daily_activities, onboarding_questions, alternative_futures) VALUES
('chef','Chef Profesional','Lifestyle','Jadilah chef profesional yang menciptakan hidangan luar biasa. Dari dapur hingga meja makan, setiap masakan adalah karya seni kuliner.','👨‍🍳','#EF4444','["Memasak hidangan pertama untuk keluarga","Lulus dari sekolah kuliner","Bekerja di restoran berbintang","Membuat menu signature sendiri","Menjadi head chef","Memenangkan kompetisi memasak","Membuka restoran sendiri"]'::jsonb,'["Cek stock bahan dapur","Persiapan mise en place","Memasak hidangan utama","Plating & presentasi","Riset resep baru","Latihan teknik memasak","Evaluasi menu"]'::jsonb,'[{"dimension": "Persiapan", "items": ["Cek stock bahan segar", "Mise en place", "Persiapan station"]},{"dimension": "Memasak", "items": ["Masak hidangan utama", "Siapkan saus + garnish", "Quality control rasa"]},{"dimension": "Kreativitas", "items": ["Riset resep baru", "Eksperimen flavor pairing", "Buat menu spesial"]},{"dimension": "Manajemen", "items": ["Inventory bahan", "Order dari supplier", "Manajemen budget dapur"]},{"dimension": "Kebersihan", "items": ["Cuci + sanitasi alat", "Cek kebersihan dapur", "Rotasi bahan kadaluarsa"]},{"dimension": "Skill", "items": ["Latihan teknik knife", "Belajar cuisine baru", "Ikut workshop kuliner"]}]'::jsonb,'[{"question": "Masakan favorit untuk dimasak?", "type": "single_select", "options": [{"label": "Indonesian", "value": "indonesian"}, {"label": "Western", "value": "western"}, {"label": "Asian", "value": "asian"}, {"label": "Pastry/Bakery", "value": "pastry"}]},{"question": "Level pengalaman memasak?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Hobi", "value": "hobi"}, {"label": "Semi-pro", "value": "semi-pro"}, {"label": "Profesional", "value": "profesional"}]},{"question": "Target utama karir chef?", "type": "single_select", "options": [{"label": "Head chef", "value": "head-chef"}, {"label": "Restoran sendiri", "value": "restoran-sendiri"}, {"label": "Food blogger", "value": "food-blogger"}, {"label": "Executive chef", "value": "executive-chef"}]},{"question": "Teknik memasak favorit?", "type": "single_select", "options": [{"label": "Grill", "value": "grill"}, {"label": "Saute", "value": "saute"}, {"label": "Bake", "value": "bake"}, {"label": "Steam", "value": "steam"}]}]'::jsonb,'[{"title": "Food Blogger/Content Creator", "description": "Membagikan resep dan tips memasak ke jutaan pengikut.", "slug": "alternative-food-blogger"},{"title": "Nutrition Consultant", "description": "Menggabungkan kuliner dengan ilmu gizi untuk menu sehat.", "slug": "alternative-nutrition-consultant"},{"title": "F&B Business Owner", "description": "Membangun bisnis restoran atau kafe dari nol.", "slug": "alternative-fnb-owner"}]'::jsonb),
('fashion-designer','Fashion Designer Profesional','Lifestyle','Jadilah fashion designer yang menciptakan tren dan gaya. Dari sketsa hingga runway, setiap koleksi adalah pernyataan fashion yang berani.','👗','#D946EF','["Membuat desain pertama","Menjahit pakaian sendiri","Mengikuti fashion show lokal","Kolaborasi dengan brand fashion","Koleksi dipakai selebriti","Fashion show di Jakarta Fashion Week","Membuka label fashion sendiri"]'::jsonb,'["Sketsa desain baru","Pilih bahan kain","Buat pola + sample","Fitting dengan model","Revisi desain","Riset tren fashion","Update portfolio"]'::jsonb,'[{"dimension": "Kreativitas", "items": ["Sketsa desain baru", "Moodboard tren terkini", "Riset fashion global"]},{"dimension": "Produksi", "items": ["Pilih bahan + kain", "Buat pola dasar", "Menjahit sample"]},{"dimension": "Fitting", "items": ["Sesi fitting model", "Adjust pattern", "Detail finishing"]},{"dimension": "Branding", "items": ["Foto koleksi", "Buat lookbook", "Update Instagram fashion"]},{"dimension": "Bisnis", "items": ["Cari supplier kain", "Manajemen produksi", "Follow up buyer"]},{"dimension": "Jaringan", "items": ["Ikut fashion event", "Kolaborasi dengan designer", "Networking buyer"]}]'::jsonb,'[{"question": "Bidang fashion favorit?", "type": "single_select", "options": [{"label": "Ready-to-wear", "value": "rtw"}, {"label": "Haute couture", "value": "haute-couture"}, {"label": "Streetwear", "value": "streetwear"}, {"label": "Accessories", "value": "accessories"}]},{"question": "Level pengalaman fashion?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Hobi", "value": "hobi"}, {"label": "Semi-pro", "value": "semi-pro"}, {"label": "Profesional", "value": "profesional"}]},{"question": "Target utama karir fashion?", "type": "single_select", "options": [{"label": "Label sendiri", "value": "label-sendiri"}, {"label": "Fashion director", "value": "fashion-director"}, {"label": "Stylist", "value": "stylist"}, {"label": "Fashion educator", "value": "fashion-educator"}]},{"question": "Tahap produksi favorit?", "type": "single_select", "options": [{"label": "Sketsa desain", "value": "sketsa"}, {"label": "Pemilihan kain", "value": "kain"}, {"label": "Menjahit", "value": "menjahit"}, {"label": "Styling", "value": "styling"}]}]'::jsonb,'[{"title": "Fashion Stylist", "description": "Menata gaya busana untuk selebriti dan majalah.", "slug": "alternative-fashion-stylist"},{"title": "Pattern Maker", "description": "Spesialis pembuatan pola pakaian untuk produksi massal.", "slug": "alternative-pattern-maker"},{"title": "Fashion Director", "description": "Memimpin arah kreatif brand fashion ternama.", "slug": "alternative-fashion-director"}]'::jsonb),
('pilot','Pilot Profesional','Lifestyle','Jadilah pilot profesional yang mengarungi angkasa. Dari takeoff hingga landing, setiap penerbangan adalah tanggung jawab dan kebanggaan.','✈️','#3B82F6','["Terbang solo pertama","Mendapat lisensi PPL","Lisensi CPL","Pertama kali terbang komersial","Jam terbang 1000 jam","Naik pangkat menjadi captain","Terbang ke 50+ destinasi"]'::jsonb,'["Cek flight plan","Pre-flight inspection","Briefing kru","Monitor cuaca","In-flight procedures","Post-flight report","Medical check rutin"]'::jsonb,'[{"dimension": "Pre-flight", "items": ["Cek flight plan", "Briefing dengan kru", "Weather check"]},{"dimension": "Inspection", "items": ["Walk-around pesawat", "Cek sistem avionik", "Fuel check"]},{"dimension": "Penerbangan", "items": ["Takeoff procedures", "Navigasi + komunikasi", "Monitor instrumen"]},{"dimension": "Landing", "items": ["Approach briefing", "Landing procedures", "Parking + shutdown"]},{"dimension": "Post-flight", "items": ["Logbook update", "Laporan teknis", "Debriefing"]},{"dimension": "Kesehatan", "items": ["Medical check rutin", "Istirahat cukup", "Manajemen jet lag"]}]'::jsonb,'[{"question": "Tipe penerbangan favorit?", "type": "single_select", "options": [{"label": "Komuter", "value": "komuter"}, {"label": "Domestik", "value": "domestik"}, {"label": "Internasional", "value": "internasional"}, {"label": "Kargo", "value": "kargo"}]},{"question": "Level lisensi pilot?", "type": "single_select", "options": [{"label": "Belum lisensi", "value": "belum"}, {"label": "PPL", "value": "ppl"}, {"label": "CPL", "value": "cpl"}, {"label": "ATPL", "value": "atpl"}]},{"question": "Target utama karir pilot?", "type": "single_select", "options": [{"label": "Garuda Indonesia", "value": "garuda"}, {"label": "Lion Air Group", "value": "lion"}, {"label": "Pesawat pribadi", "value": "pribadi"}, {"label": "Instructor", "value": "instructor"}]},{"question": "Aspek terpenting sebagai pilot?", "type": "single_select", "options": [{"label": "Keamanan", "value": "keamanan"}, {"label": "Ketepatan", "value": "ketepatan"}, {"label": "Komunikasi", "value": "komunikasi"}, {"label": "Ketenangan", "value": "ketenangan"}]}]'::jsonb,'[{"title": "Flight Instructor", "description": "Melatih dan mendidik calon pilot baru.", "slug": "alternative-flight-instructor"},{"title": "Aviation Manager", "description": "Mengelola operasional penerbangan di maskapai.", "slug": "alternative-aviation-manager"},{"title": "Airline Executive", "description": "Berkarir di manajemen maskapai penerbangan.", "slug": "alternative-airline-executive"}]'::jsonb)
